@using sv_be73b5575704447ab98cbf2777f465ba.Services

<div class="card h-100 product-card" @onclick="HandleCardClick" role="button">
    <div class="card-img-top bg-secondary bg-opacity-25 d-flex align-items-center justify-content-center"
         style="height: 180px;">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="text-success fw-bold mb-1">@Product.Price.ToString("C")</p>
        <p class="mb-1">@RatingStars</p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-primary btn-sm mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private string RatingStars
    {
        get
        {
            int filled = (int)Math.Round(Product.Rating);
            return new string('★', filled) + new string('☆', 5 - filled);
        }
    }

    private async Task HandleCardClick() => await OnSelected.InvokeAsync(Product);

    private async Task HandleAddToCart() => await OnAddToCart.InvokeAsync(Product);
}

@using sv_be73b5575704447ab98cbf2777f465ba.Services

@if (Products.Count == 0)
{
    <div class="alert alert-info">No products found matching your criteria.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3">
        @foreach (var product in Products)
        {
            <div class="col">
                <ProductCard Product="product"
                             OnSelected="OnProductSelected"
                             OnAddToCart="OnAddToCart" />
            </div>
        }
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = [];

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@using sv_be73b5575704447ab98cbf2777f465ba.Services

<div class="p-3">
    <h5 class="mb-3">Filters</h5>

    @if (Categories.Count > 0)
    {
        <h6>Category</h6>
        <div class="mb-3">
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                           checked="@SelectedCategories.Contains(category)"
                           @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        </div>
    }

    <h6>Price Range</h6>
    <div class="mb-2">
        <label class="form-label small">Min Price</label>
        <input type="number" class="form-control form-control-sm" step="0.01" min="0"
               value="@MinPrice" @onchange="@(e => MinPrice = ParseDecimal(e.Value))" />
    </div>
    <div class="mb-3">
        <label class="form-label small">Max Price</label>
        <input type="number" class="form-control form-control-sm" step="0.01" min="0"
               value="@MaxPrice" @onchange="@(e => MaxPrice = ParseDecimal(e.Value))" />
    </div>

    <div class="form-check mb-3">
        <input class="form-check-input" type="checkbox" id="inStockOnly"
               checked="@InStockOnly" @onchange="@(e => InStockOnly = (bool)e.Value!)" />
        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public EventCallback<ProductFilter> OnApplyFilters { get; set; }

    [Parameter]
    public EventCallback OnClearFilters { get; set; }

    private HashSet<string> SelectedCategories { get; set; } = [];
    private decimal? MinPrice { get; set; }
    private decimal? MaxPrice { get; set; }
    private bool InStockOnly { get; set; }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            SelectedCategories.Add(category);
        else
            SelectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: SelectedCategories.Count > 0 ? SelectedCategories.ToList() : null,
            MinPrice: MinPrice,
            MaxPrice: MaxPrice,
            InStockOnly: InStockOnly
        );
        await OnApplyFilters.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        SelectedCategories.Clear();
        MinPrice = null;
        MaxPrice = null;
        InStockOnly = false;
        await OnClearFilters.InvokeAsync();
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@page "/catalog"
@using sv_be73b5575704447ab98cbf2777f465ba.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

@if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogFilters Categories="categories"
                            OnApplyFilters="HandleApplyFilters"
                            OnClearFilters="HandleClearFilters" />
        </div>

        <div class="col-md-9">
            @if (isLoading)
            {
                <div class="d-flex justify-content-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
            else if (result is not null)
            {
                <CatalogToolbar SortBy="@sortBy"
                                TotalCount="result.TotalCount"
                                Page="currentPage"
                                PageSize="PageSize"
                                OnSortChanged="HandleSortChanged" />

                <ProductGrid Products="result.Items"
                             OnProductSelected="OnProductSelected"
                             OnAddToCart="HandleAddToCart" />

                @if (result.TotalCount > 0)
                {
                    <CatalogPagination Page="currentPage"
                                       TotalPages="totalPages"
                                       OnPageChanged="HandlePageChanged" />
                }
            }
        </div>
    </div>
}

@code {
    private const int PageSize = 12;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string> categories = [];
    private PagedResult<Product>? result;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private int totalPages = 1;
    private bool isLoading;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadInitialDataAsync();
    }

    private async Task LoadInitialDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            categories = await categoriesTask;
            result = await searchTask;
            CalculateTotalPages();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
            CalculateTotalPages();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleClearFilters()
    {
        currentFilter = new ProductFilter(null, null, null, false);
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchAsync();
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }

    private async Task RetryAsync() => await LoadInitialDataAsync();

    private void CalculateTotalPages()
    {
        totalPages = result is null || result.TotalCount == 0
            ? 1
            : (int)Math.Ceiling((double)result.TotalCount / PageSize);
    }
}

